using System; using System.Net.Http; using System.Net.Http.Headers; using System.Text; using System.Text.Json; using System.Threading.Tasks; class Program { static async Task Main() { HttpClient client = new HttpClient(); client.BaseAddress = new Uri("https://localhost:7047/"); var handler = new HttpClientHandler { ServerCertificateCustomValidationCallback = (m,c,ch,e) => true }; client = new HttpClient(handler) { BaseAddress = new Uri("https://localhost:7047/") }; var loginBody = new StringContent("{\"correo\":\"admin@sigebi.com\",\"contrasena\":\"Admin123!\"}", Encoding.UTF8, "application/json"); var loginRes = await client.PostAsync("api/Auth/login", loginBody); var tokenRaw = await loginRes.Content.ReadAsStringAsync(); var token = JsonSerializer.Deserialize<JsonElement>(tokenRaw).GetProperty("token").GetString(); client.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue("Bearer", token); var getRes = await client.GetAsync("api/Recursos"); var recsRaw = await getRes.Content.ReadAsStringAsync(); var recs = JsonSerializer.Deserialize<JsonElement>(recsRaw); string id = ""; foreach(var r in recs.EnumerateArray()) { if(r.GetProperty("tipoRecurso").GetString() == "Libro") { id = r.GetProperty("id").GetString(); break; } } if(id=="") { Console.WriteLine("No ext. Libros"); return; } Console.WriteLine("ID Libro: " + id); var form = new MultipartFormDataContent(); form.Add(new StringContent("Libro Test"), "Titulo"); form.Add(new StringContent("Autor Test"), "Autor"); form.Add(new StringContent("1"), "CategoriaId"); form.Add(new StringContent("5"), "Stock"); form.Add(new StringContent("1234"), "ISBN"); form.Add(new StringContent("EDITORIAL PRUEBA WRAPPER"), "Editorial"); form.Add(new StringContent("2000"), "Anio"); var putRes = await client.PutAsync($"api/Recursos/libro/{id}", form); Console.WriteLine("PUT Status: " + putRes.StatusCode); var get2Res = await client.GetAsync("api/Recursos"); var recs2Raw = await get2Res.Content.ReadAsStringAsync(); var recs2 = JsonSerializer.Deserialize<JsonElement>(recs2Raw); foreach(var r in recs2.EnumerateArray()) { if(r.GetProperty("id").GetString() == id) { Console.WriteLine("Editorial Post-Update: " + r.GetProperty("editorial").GetString()); return; } } } }
